import java.util.ArrayList;
import java.util.LinkedList;
import java.util.List;
import java.util.Queue;

class Node {
    public int val;
    public List<Node> children;

    public Node() {}

    public Node(int _val) {
        val = _val;
        children = new ArrayList<Node>();
    }

    public Node(int _val, List<Node> _children) {
        val = _val;
        children = _children;
    }
};

public List<List<Integer>> levelOrder(Node root) {
    List<List<Integer>> result = new ArrayList<>();
    if (root == null) return result;

    Queue<Node> queue = new LinkedList<>();
    queue.add(root);

    while (!queue.isEmpty()) {
        int size = queue.size();
        List<Integer> currentLevel = new ArrayList<>();

        for (int i = 0; i < size; i++) {
            Node currentNode = queue.poll();
            currentLevel.add(currentNode.val);
            for (Node child : currentNode.children) {
                queue.add(child);
            }
        }
        result.add(currentLevel);
    }

    return result;
}
```

    The algorithm uses an approach similar to a breadth-first search (BFS) to traverse the tree. We start at the root and use a queue to store the nodes to be visited. While the queue is not empty, we iterate over each node at the current level and add its children to the next level. After processing all nodes at the current level, we add their values to the result, and the next level becomes the current level. This continues until we have processed all levels in the tree. In the end, we return the result as a list of lists containing the nodes' values.
